# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt
import requests
from functools import wraps

app = Flask(__name__)

def validate_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401
        
        token = auth_header.split(' ')[1]
        try:
            # In development, we skip signature verification for speed
            payload = jwt.decode(token, options={"verify_signature": False})
            request.user_claims = payload
        except jwt.PyJWTError:
            return jsonify({'error': 'Invalid token'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/<path:service_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@validate_token
def proxy(service_path):
    backend_url = f"http://backend-service/{service_path}"
    
    # Forward request with user claims in headers
    headers = {}
    if hasattr(request, 'user_claims'):
        headers['X-User-Claims'] = str(request.user_claims)
    
    try:
        response = requests.request(
            method=request.method,
            url=backend_url,
            headers=headers,
            json=request.get_json() if request.is_json else None
        )
        return jsonify(response.json()), response.status_code
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)